package v1

import (
	"encoding/json"
	"fmt"
	"time"
)

// Matcher represents a matcher for silence matching rules
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// Validate checks if a matcher is valid
func (m *Matcher) Validate() error {
	if m.Name == "" {
		return fmt.Errorf("matcher name cannot be empty")
	}
	return nil
}

// SilenceRequest represents a silence request for creation
type SilenceRequest struct {
	Matchers  []Matcher `json:"matchers"`
	StartsAt  time.Time `json:"startsAt"`
	EndsAt    time.Time `json:"endsAt"`
	CreatedBy string    `json:"createdBy"`
	Comment   string    `json:"comment"`
}

// Validate checks if a silence request is valid
func (s *SilenceRequest) Validate() error {
	if len(s.Matchers) == 0 {
		return fmt.Errorf("matchers cannot be empty")
	}

	for i, m := range s.Matchers {
		if err := m.Validate(); err != nil {
			return fmt.Errorf("matcher at index %d: %w", i, err)
		}
	}

	if s.StartsAt.IsZero() {
		return fmt.Errorf("startsAt cannot be empty")
	}

	if s.EndsAt.IsZero() {
		return fmt.Errorf("endsAt cannot be empty")
	}

	if s.EndsAt.Before(s.StartsAt) {
		return fmt.Errorf("endsAt must be after startsAt")
	}

	if s.CreatedBy == "" {
		return fmt.Errorf("createdBy cannot be empty")
	}

	return nil
}

// SilenceResponse represents a created silence with its ID
type SilenceResponse struct {
	ID string `json:"id"`
}

// BulkSilencesResponse represents the response for bulk silence creation
type BulkSilencesResponse struct {
	SilenceIDs []string `json:"silenceIDs"`
}

// BulkSilenceError represents an error for a specific silence in the bulk request
type BulkSilenceError struct {
	Index int    `json:"index"`
	Error string `json:"error"`
}

// silencesBulk handles the bulk creation of silences
func (api *API) silencesBulk(r *http.Request) apiFuncResult {
	var silences []SilenceRequest

	// Parse the request body
	if err := json.NewDecoder(r.Body).Decode(&silences); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error parsing JSON: %w", err)}, nil, nil}
	}

	// Check if array is empty
	if len(silences) == 0 {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("silences array cannot be empty")}, nil, nil}
	}

	// Validate all silences first (atomic semantics)
	validationErrors := []BulkSilenceError{}
	for i, silence := range silences {
		if err := silence.Validate(); err != nil {
			validationErrors = append(validationErrors, BulkSilenceError{
				Index: i,
				Error: err.Error(),
			})
		}
	}

	// If there are validation errors, return them immediately
	if len(validationErrors) > 0 {
		errorResponse := map[string]interface{}{
			"status": "error",
			"errors": validationErrors,
		}
		return apiFuncResult{errorResponse, &apiError{errorBadData, fmt.Errorf("validation failed for %d silence(s)", len(validationErrors))}, nil, nil}
	}

	// Create all silences (in practice, this would call alertmanager API)
	silenceIDs := make([]string, len(silences))
	for i := range silences {
		// Generate silence IDs (in practice, this would be done by alertmanager)
		// For now, we use a simple hash-based approach
		silenceID := generateSilenceID(silences[i], i)
		silenceIDs[i] = silenceID
	}

	response := BulkSilencesResponse{
		SilenceIDs: silenceIDs,
	}

	return apiFuncResult{response, nil, nil, nil}
}

// generateSilenceID generates a unique ID for a silence
// In a real implementation, this would be provided by the alertmanager
func generateSilenceID(s SilenceRequest, index int) string {
	// Simple ID generation for demonstration
	return fmt.Sprintf("silence_%d_%d", index, time.Now().Unix())
}

