				Matchers:  []Matcher{{Name: "job", Value: "test"}},
				StartsAt:  time.Time{},
				EndsAt:    now.Add(1 * time.Hour),
				CreatedBy: "user",
				Comment:   "Test",
			},
			wantErr: true,
		},
		{
			name: "Empty endsAt",
			silence: SilenceRequest{
				Matchers:  []Matcher{{Name: "job", Value: "test"}},
				StartsAt:  now,
				EndsAt:    time.Time{},
				CreatedBy: "user",
				Comment:   "Test",
			},
			wantErr: true,
		},
		{
			name: "EndsAt before startsAt",
			silence: SilenceRequest{
				Matchers:  []Matcher{{Name: "job", Value: "test"}},
				StartsAt:  now.Add(1 * time.Hour),
				EndsAt:    now,
