				Comment:   "Test",
			},
			wantErr: true,
		},
		{
			name: "Empty createdBy",
			silence: SilenceRequest{
				Matchers:  []Matcher{{Name: "job", Value: "test"}},
				StartsAt:  now,
				EndsAt:    now.Add(1 * time.Hour),
				CreatedBy: "",
				Comment:   "Test",
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
