func TestMatcher_Validate(t *testing.T) {
	tests := []struct {
		name    string
		matcher Matcher
		wantErr bool
	}{
		{
			name:    "Valid matcher",
			matcher: Matcher{Name: "job", Value: "test", IsRegex: false},
			wantErr: false,
		},
		{
			name:    "Valid regex matcher",
			matcher: Matcher{Name: "instance", Value: ".*:9090", IsRegex: true},
			wantErr: false,
		},
		{
			name:    "Empty name",
			matcher: Matcher{Name: "", Value: "test", IsRegex: false},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.matcher.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

